import express from"express";import{Server}from"socket.io";import cors from"cors";import http from"http";import{connect}from"./config.js";import{chatModel}from"./chat.schema.js";let app=express(),server=http.createServer(app),io=new Server(server,{cors:{origin:"*",methods:["GET","POST"]}});io.on("connection",s=>{console.log("Connection is established"),s.on("join",e=>{s.username=e,chatModel.find().sort({timestamp:1}).limit(50).then(e=>{s.emit("load_messages",e)}).catch(e=>{console.log(e)})}),s.on("new_message",e=>{var o={username:s.username,message:e};new chatModel({username:s.username,message:e,timestamp:new Date}).save(),s.broadcast.emit("broadcast_message",o)}),s.on("disconnect",()=>{console.log("Connection is disconnected")})}),server.listen(8080,()=>{console.log("App is listening on 8080"),connect()});